-- StarterGui.TargetingGui.TargetingCore
--
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")
local CollectionService = game:GetService("CollectionService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Players = game:GetService("Players")
local Marker = script.Parent:WaitForChild("Marker")
local Frame = Marker:WaitForChild("Frame")
local OuterFrame = Marker:WaitForChild("OuterFrame")
local Cursor = Marker:WaitForChild("Cursor")
local LocalPlayer = Players.LocalPlayer
local v1 = LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait()
local CurrentCamera = workspace.CurrentCamera
local Mods = ReplicatedStorage:WaitForChild("Mods")
local Raycast = require(Mods:WaitForChild("Raycast"))
local v2 = false

local function FadeIn() --[[ FadeIn | Line: 28 | Upvalues: v2 (ref), TweenService (copy), Frame (copy), OuterFrame (copy), Cursor (copy), Marker (copy) ]]
	v2 = true
	TweenService:Create(Frame, TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
		Size = UDim2.new(0.4, 0, 0.4, 0)
	}):Play()
	TweenService:Create(OuterFrame, TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
		Size = UDim2.new(0.75, 0, 0.75, 0)
	}):Play()
	TweenService:Create(Cursor, TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
		Rotation = -135,
		TextTransparency = 0,
		Size = UDim2.new(0.5, 0, 0.5, 0)
	}):Play()
	TweenService:Create(Marker, TweenInfo.new(0.25, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
		Enabled = true
