-- Players.Noriko_Ellen.PlayerScripts.KeycardReaderDisplayHandler
--
local CollectionService = game:GetService("CollectionService")
local tbl = {}
local CurrentCamera = workspace.CurrentCamera

local function AddScreen(p1) --[[ AddScreen | Line: 14 | Upvalues: tbl (copy) ]]
	if tbl[p1] then
		return
	end

	tbl[p1] = {
		Bar1 = p1:WaitForChild("Cooldown"):WaitForChild("Bar1"),
		Bar2 = p1:WaitForChild("Cooldown"):WaitForChild("Bar2")
	}
	tbl[p1].Bar1.Size = UDim2.new(0.1, 0, 0, 0)
	tbl[p1].Bar2.Size = UDim2.new(0.1, 0, 0, 0)
end

for k, v in pairs(CollectionService:GetTagged("KeycardReaderScreen")) do
	AddScreen(v)
end

CollectionService:GetInstanceAddedSignal("KeycardReaderScreen"):Connect(AddScreen)
CollectionService:GetInstanceRemovedSignal("KeycardReaderScreen"):Connect(function(p1) --[[ Line: 32 | Upvalues: tbl (copy) ]]
	if not tbl[p1] then
		return
	end

	tbl[p1] = nil
end)

while task.wait(1) do
	local v1 = workspace:GetServerTimeNow()

	for k, v in pairs(tbl) do
		if (k.Position - CurrentCamera.CFrame.Position).Magnitude < 25 then
			local v2 = k:GetAttribute("CooldownStart") or 1
			local v4 = math.clamp((v1 - v2) / ((k:GetAttribute("CooldownEnd") or 1) - v2), 0, 1)

			v.Bar1.Size = UDim2.new(0.1, 0, v4, 0)
			v.Bar2.Size = UDim2.new(0.1, 0, v4, 0)
		end
	end
end

