while task.wait(0.05) do
	local v7

	if v2 then
		if not v4 then
			local Target = v1.Target
			local v8 = if Target then Target:FindFirstAncestorWhichIsA("Model") else Target

			v7 = if v8 and (v8:FindFirstChild("Humanoid") and v8:FindFirstChild("HumanoidRootPart")) then v8 else nil
			v5 = if v3.Using.OnOthers and (v7 and (v7.HumanoidRootPart.Position - HumanoidRootPart.Position).magnitude <= 6) then v7.Humanoid else Humanoid
		end

		if v5 then
			if t2.Run then
				local Sprinting = _G.CharacterStates.Sprinting

				if Sprinting and not t2.Run.IsPlaying then
					t2.Run:Play(0.1)
				elseif not Sprinting and t2.Run.IsPlaying then
					t2.Run:Stop(0.1)
				end
			end

			Highlight.Adornee = v5.Parent

			if Highlight.Adornee and (Highlight.Adornee:FindFirstChild("HumanoidRootPart") and (Highlight.Adornee.HumanoidRootPart.Position - HumanoidRootPart.Position).Magnitude > 10) then
				v4 = false

