					Events.Items.Use:FireServer(false)
				end
			end

			if v3.Using.FullHealth or not (v5.Health >= v5.MaxHealth) then
				local Default = t.Default

				if Default == v6 then
					continue
				end

				v6 = Default
				Highlight.OutlineColor = Default
				Highlight.FillColor = Default

				continue
			end

			local FullHealth = t.FullHealth

			if FullHealth == v6 then
				continue
			end

			v6 = FullHealth
