			Areas = {}
		})
	end
end

for k, v in pairs(StreamingInformation) do
	for k2, v2 in pairs(v.Targets) do
		for k3, v3 in pairs(v2:GetDescendants()) do
			if (v3:IsA("BasePart") or (v3:IsA("Decal") or v3:IsA("Texture"))) and not v3:HasTag("DynamicIgnore") then
