-- StarterGui.ExtraUI.ContextProducts.ContextProductsCore
--
repeat
	task.wait(0.1)
until game.ReplicatedFirst:GetAttribute("GameLoaded")

local MarketplaceService = game:GetService("MarketplaceService")

game:GetService("Players")

local Players = game.Players
local ReplicatedStorage = game.ReplicatedStorage
local Mods = ReplicatedStorage:WaitForChild("Mods")
local Purchase = ReplicatedStorage:WaitForChild("Events"):WaitForChild("Purchase")
local LocalPlayer = Players.LocalPlayer

LocalPlayer:WaitForChild(Players:GetAttribute("PLAYER_STORAGE"))

local Sounds = script:WaitForChild("Sounds")
local Frames = script:WaitForChild("Frames")
local ProductShared = require(Mods:WaitForChild("ProductShared"))
local v1 = script.Parent
local TopBar = v1:WaitForChild("TopBar")
local List = v1:WaitForChild("List")
local v2 = false
local v3 = false
local tbl = {}

local function CreateButton(p1, p2, p3, p4) --[[ CreateButton | Line: 46 | Upvalues: MarketplaceService (copy), Frames (copy), Sounds (copy), v2 (ref), v3 (ref), ReplicatedStorage (copy) ]]
	local ok, result = pcall(MarketplaceService.GetProductInfo, MarketplaceService, p2.ID, p3)

	if not ok then
		warn("UNABLE TO GET PRODUCT DATA!")

		return
	end

	local v1 = Frames:WaitForChild("ProductButton"):Clone()

	v1.Visible = false
	v1.IconFrame.Title.Text = result.Name
	v1.IconFrame.Description.Text = result.Description or "NO DESCRIPTION"
	v1.IconFrame.Icon.Image = "rbxassetid://" .. (result.IconImageAssetId ~= 0 and result.IconImageAssetId or 8681682276)
	v1.ButtonFrame.PriceText.Text = p2.Tokens > 0 and p2.Tokens .. " TOKEN(s)" or result.PriceInRobux .. " R$"
	v1.ButtonFrame.ActionText.Text = if p2.Owned then "OWNED" else "BUY"
	v1.LayoutOrder = result.PriceInRobux
	v1.Parent = p4
	v1.MouseButton1Click:Connect(function() --[[ Line: 69 | Upvalues: Sounds (ref), v2 (ref), v3 (ref), ReplicatedStorage (ref), p1 (copy) ]]
		Sounds.Click:Play()

		if v2 then
			return
		end

		if not v3 then
			v3 = true
			task.delay(0.25, function() --[[ Line: 75 | Upvalues: v3 (ref) ]]
				v3 = false
			end)
			ReplicatedStorage:WaitForChild("PromptPurchase"):Fire(p1)
		end
	end)

	return v1
end

local function ClearButtons(p1, p2) --[[ ClearButtons | Line: 85 | Upvalues: tbl (ref) ]]
	for k, v in pairs(p1:GetChildren()) do
		if v:IsA("TextButton") and (not p2 or v.Name == p2) then
			v:Destroy()
		end
	end

	tbl = {}
end

local function UpdatePurchaseables() --[[ UpdatePurchaseables | Line: 96 | Upvalues: Purchase (copy), ClearButtons (copy), List (copy), CreateButton (copy), tbl (ref) ]]
	local v1 = Purchase:WaitForChild("GetAvailable"):InvokeServer()

	ClearButtons(List)

	for k, v in pairs(v1) do
		for k2, v2 in pairs(v) do
			if v2.Context then
				local v22 = CreateButton(k2, v2, Enum.InfoType.Product, List)

				if v22 then
					tbl[v22] = v2
				end
			end
		end
	end
end

MarketplaceService.PromptProductPurchaseFinished:Connect(function() --[[ Line: 119 | Upvalues: v2 (ref), Purchase (copy) ]]
	v2 = false
	Purchase.GiftTarget:FireServer()
end)

local sum = 0

while task.wait(0.5) do
	if sum <= 0 then
		UpdatePurchaseables()
		sum = 30
	end

	local count = 0

	sum = sum - 0.5

	for k, v in pairs(tbl) do
		local ok, result, result2 = pcall(ProductShared[v.Context], LocalPlayer)

		if ok then
			k.Visible = if result then not result2 else result

			if k.Visible then
				count = count + 1
			end

			continue
		end

		warn("[CONTEXT PRODUCT ERROR]:", result)
	end

	if TopBar.Visible ~= (if count > 0 then true else false) then
		TopBar.Visible = if count > 0 then true else false
		v1.Interactable = if count > 0 then true else false
	end
end

