-- ReplicatedStorage.GunStorage.Mods.Shared
--
local t = {}
local Mods = game.ReplicatedStorage:WaitForChild("Mods")
local Shared = require(Mods.ItemDatabase:WaitForChild("Shared"))

function t.SetupFiringStats(p1, p2) --[[ SetupFiringStats | Line: 12 | Upvalues: Shared (copy) ]]
	local t = {}

	for k, v in pairs(p1.DefaultFiring) do
		t[k] = p2 and p2.Firing[k] or v
	end

	if p2 then
		for k, v in pairs(p2.Firing) do
			if not t[k] then
				t[k] = v
			end
		end
	end

	p1.Firing = Shared.GetAdjustedStats(t, p1.AttachmentStats)
end

return t
